    private const LOG_FILE = 'delete_from_blacklist';

    /** @var int Максимальное время выполнения скрипта (в секундах) */
    private const MAX_EXECUTION_TIME = 3500;

    public function run()
    {
        if (session_status() === PHP_SESSION_ACTIVE) {
            session_write_close();
        }

        $this->logging(__METHOD__, '', 'Начало выполнения скрипта', '', self::LOG_FILE);

        $executionStartTime = microtime(true);

        $manager = $this->managers->get_manager($this->managers::MANAGER_SYSTEM_ID);

        if (empty($manager)) {
            $this->logging(__METHOD__, '', 'Менеджер не найден', ['manager' => $manager], self::LOG_FILE);
            return;
        }

        foreach (self::USERS_ID_TO_DELETE_FROM_BLACKLIST as $userId) {
            try {
                if (microtime(true) - $executionStartTime > self::MAX_EXECUTION_TIME) {
                    $this->logging(__METHOD__, '', '',
                        'Достигнута максимальная продолжительность работы крон', self::LOG_FILE);
                    break;
                }

                $this->logging(__METHOD__, '', 'Начата обработка пользователя', ['user_id' => $userId], self::LOG_FILE);

                $user = $this->users->get_user($userId);
                if (empty($user)) {
                    $this->logging(__METHOD__, '', 'Пользователь не найден', ['user_id' => $userId, 'user' => $user], self::LOG_FILE);
                    continue;
                }

                if ($this->hasAlreadyGeneratedAutoApproveOrder($user)) {
                    continue;
                }

//                $this->deleteUserFromBlacklist($user, $manager);

                $this->generateAutoApproveOrder($user);
            } catch (Throwable $error) {
                $this->logging(__METHOD__, '', 'Фатальная ошибка', ['user_id' => $userId, 'error' => $error], self::LOG_FILE);
            }
        }

        $this->logging(__METHOD__, '', 'Завершено выполнение скрипта', '', self::LOG_FILE);
    }

    private function hasAlreadyGeneratedAutoApproveOrder(stdClass $user): bool
    {
        $query = $this->db->placehold("
            SELECT ca.id
            FROM __contracts c
                     INNER JOIN __contracts_for_auto_approve_orders ca ON ca.contract_number = c.number
            WHERE c.user_id = ?
              AND ca.date_create > '2026-02-04 00:00:00';
        ", (int)$user->id);
        $this->db->query($query);
        $result = $this->db->result();
        return !empty($result);
    }

    private function deleteUserFromBlacklist(stdClass $user, stdClass $manager)
    {
        // Удаление пользователя из ЧС
        $this->blacklist->delete($user->id);
        $this->blacklist->sendDeleteUserFromBlacklist1c($user->UID, '', 'Амнистия по ЧС по базе клиентов от 2025-12-01', $manager->name_1c);

        $this->logging(__METHOD__, '', 'Пользователь удален из ЧС', ['user_id' => $user->id], self::LOG_FILE);

        // Чтобы не было слишком много запросов в 1C
        sleep(1);
    }

    private function generateAutoApproveOrder(stdClass $user)
    {
        $contracts = $this->contracts->get_contracts([
            'user_id' => $user->id,
            'limit' => 1
        ]);

        if (empty($contracts[0])) {
            $this->logging(__METHOD__, '', 'У пользователя нет договоров', ['user_id' => $user->id, 'contracts' => $contracts], self::LOG_FILE);
            return;
        }

        $lastContract = $contracts[0];

        // Добавление записи в s_contracts_for_auto_approve_orders для генерации автозаявки
        $query = $this->db->placehold("INSERT INTO __contracts_for_auto_approve_orders (contract_number, status) VALUES(?, 'NEW')", $lastContract->number);
        $this->db->query($query);
        $recordId = $this->db->insert_id();

        $this->logging(__METHOD__, '', 'Добавлена запись для генерации автозаявки', ['user_id' => $user->id, 'last_contract_number' => $lastContract->number, 'record_id' => $recordId], self::LOG_FILE);
    }
}

$deleteFromBlacklist = new DeleteFromBlacklist();
$deleteFromBlacklist->run();